

--
-- Table structure for table `user`
--

DROP TABLE IF EXISTS `user`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `user` (
  `createdAt` datetime(6) NOT NULL DEFAULT CURRENT_TIMESTAMP(6),
  `updatedAt` datetime(6) NOT NULL DEFAULT CURRENT_TIMESTAMP(6) ON UPDATE CURRENT_TIMESTAMP(6),
  `deletedAt` datetime(6) DEFAULT NULL,
  `id` int NOT NULL AUTO_INCREMENT,
  `nom` varchar(255) NOT NULL,
  `signature` text,
  `postnom` varchar(255) DEFAULT NULL,
  `prenom` varchar(255) NOT NULL,
  `email` varchar(255) DEFAULT NULL,
  `sexe` char(1) NOT NULL,
  `telephone` varchar(255) DEFAULT NULL,
  `otp` text,
  `username` varchar(255) NOT NULL,
  `password` varchar(255) NOT NULL DEFAULT 'N/A',
  `isSupervisor` tinyint NOT NULL DEFAULT '0',
  `isActive` tinyint NOT NULL DEFAULT '0',
  `status` tinyint NOT NULL DEFAULT '1',
  `directionId` int DEFAULT NULL,
  `serviceId` int DEFAULT NULL,
  `divisionId` int DEFAULT NULL,
  `division` varchar(255) DEFAULT NULL,
  `service` varchar(255) DEFAULT NULL,
  `direction` varchar(255) DEFAULT NULL,
  `fonction` varchar(255) DEFAULT NULL,
  `grade` varchar(255) DEFAULT NULL,
  `directeurId` int DEFAULT NULL,
  `agentDelegueId` int DEFAULT NULL,
  `directionGeneraleId` int DEFAULT NULL,
  `isSetPassword` tinyint NOT NULL DEFAULT '0',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=375 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

